import java.util.stream.IntStream;

public class Main {
    public static void main(String[] args) {
        // Define the given value
        int givenValue = 5;

        // Use IntStream to generate a stream of integers
        IntStream stream = IntStream.range(1, 11); // Generate numbers from 1 to 10

        // Filter the stream to get integers greater than the given value
        stream.filter(i -> i > givenValue)
              .forEach(System.out::println);

        // Alternatively, you can use a lambda expression to filter the stream
        IntStream stream2 = IntStream.range(1, 11);
        stream2.filter(i -> i > givenValue)
