```python
import os
import functools
import pickle

def file_cache(maxsize=128):
    """A file-based cache decorator with a maximum size."""
    cache_dir = 'cache'

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = str(args) + str(kwargs)
            cache_file = os.path.join(cache_dir, cache_key + '.pkl')

            if os.path.exists(cache_file):
                with open(cache_file, 'rb') as f:
                    return pickle.load(f)

            result = func(*args, **kwargs)
            with open(cache_file, 'wb') as f:
                pickle.dump(result, f)

            # Remove the oldest cache files when the cache is full
            if len(os.listdir(cache_dir)) > maxsize:
                oldest_files = sorted(os.listdir(cache_dir), key=lambda x: os.path.getctime(os.path.join(cache_dir, x)))
                oldest_files = oldest_files[:-maxsize

