import { useContext, createContext } from 'react'
import NotificationContext from './notification.context'

interface NotificationProps {
  heading: string
  subheading: string
  type: string
}

interface UseNotificationResult {
  notify: (props: NotificationProps) => Promise<void>
}

const useNotification = (): UseNotificationResult => {
  const notificationElem = useContext(NotificationContext)

  const notify = async (props: NotificationProps): Promise<void> => {
    if (!notificationElem) return

    const { heading, subheading, type } = props
    await notificationElem.open({
      heading,
      subheading,
      type,
    })
  }

  return { notify }
}

export default useNotification
